B.B=new A.oB(1,"rule")
B.QM=new A.T(B.B,"Formation Rule","**Active:** Subject + **verb** + object\n**Passive:** Object + **be** + past participle (+ by + agent)\n\n**Tense mapping:**\n\u2022 Simple Present \u2192 is/are + V3\n\u2022 Simple Past \u2192 was/were + V3\n\u2022 Must/Should \u2192 must/should + be + V3\n\u2022 Has/Have \u2192 has/have + been + V3",null,null,null)
B.ad=new A.oB(2,"examples")
B.Ku=new A.aE(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla \xe7al\u0131\u015ft\u0131r\u0131l\u0131r.","is driven")
B.JV=new A.aE("All maintenance tasks must be performed in accordance with the AMM.","T\xfcm bak\u0131m g\xf6revleri AMM'ye uygun \u015fekilde ger\xe7ekle\u015ftirilmelidir.","must be performed")
B.KS=new A.aE("The fuel filter is replaced every 500 flight hours.","Yak\u0131t filtresi her 500 u\xe7u\u015f saatinde de\u011fi\u015ftirilir.","is replaced")
B.K0=new A.aE("Warning notices must be placed in the cockpit before maintenance.","Bak\u0131mdan \xf6nce kokpite uyar\u0131 levhalar\u0131 yerle\u015ftirilmelidir.","must be placed")
