B.QA=new A.T(B.ac,"Safety equipment names must be exact","Using incorrect names for safety equipment can cause dangerous misunderstandings. Exam questions test precise knowledge of equipment names, their function, and the verbs used with them.\n\nThis lesson covers the most frequently examined safety equipment terms across all aviation roles.",null,null,null)
B.QZ=new A.T(B.B,"\ud83d\udee1\ufe0f Cabin Safety Equipment","**Portable oxygen unit** \u2014 portable O\u2082 bottle for crew use\n**Drop-down oxygen mask** \u2014 passenger masks, auto-deploys above 10,000 ft cabin alt\n**Life vest / Life jacket** \u2014 under-seat flotation device\n**Emergency exit** \u2014 floor-level lighting marks the path\n**Escape slide** \u2014 inflatable slide for rapid evacuation\n**Fire extinguisher** \u2014 Halon type in cockpit, water/CO\u2082 in cabin\n**ELT** \u2014 Emergency Locator Transmitter (activates on impact)",null,null,null)
B.R9=new A.T(B.B,"\ud83d\udd27 Technical Safety Equipment","**Circuit breaker (CB)** \u2014 protects electrical circuits from overload\n**Fire detector** \u2014 senses smoke/heat in engine, APU, cargo compartment\n**Fire suppression system** \u2014 discharges extinguisher agent into engine nacelle\n**Overheat detector** \u2014 warns of bleed air duct overheating\n**TCAS** \u2014 Traffic Collision Avoidance System\n**GPWS/EGPWS** \u2014 Ground Proximity Warning System",null,null,null)
B.Kd=new A.aE("Oxygen masks will drop down automatically if cabin altitude exceeds 10,000 feet.","Kabin irtifas\u0131 10.000 fiti a\u015farsa oksijen maskeleri otomatik olarak d\xfc\u015fer.","drop down automatically")
B.L5=new A.aE("The fire suppression system discharged successfully into the engine nacelle.","Yang\u0131n bast\u0131rma sistemi motor kovan\u0131na ba\u015far\u0131yla de\u015farj edildi.","fire suppression system")
B.Kk=new A.aE("All cabin crew must demonstrate the life vest donning procedure to passengers.","T\xfcm kabin ekibi yolculara can yele\u011fi giyinme prosed\xfcr\xfcn\xfc g\xf6stermelidir.","donning procedure")
B.Ws=s([B.Kd,B.L5,B.Kk],t.l)
B.PR=new A.T(B.ad,"Safety Equipment in Use",null,B.Ws,null,null)
B.PC=new A.T(B.ae,"\u2708\ufe0f Exam Tip",'Key verbs used with safety equipment:\n\u2022 **don** = put on (life vest, oxygen mask) \u2014 formal aviation term\n\u2022 **deploy** = activate automatically (escape slide, oxygen mask)\n\u2022 **arm** = set to automatic deployment mode (door slide)\n\u2022 **discharge** = release extinguishing agent\n\u2022 **arm/disarm** doors = cabin crew action before departure/after arrival\n\nNever use "put on" in formal exam answers \u2014 use **don**.',null,null,null)
B.UX=s(["Wearing","Donning","Fitting","Applying"],t.s)
B.a2w=new A.ab(-140,B.ai,270,'The correct aviation term for "putting on" a life vest or oxygen mask is:',B.UX,1,B.L,null,null,null)
B.V9=s(["Traffic Control and Safety System","Traffic Collision Avoidance System","Terminal Control Area Separation","Tactical Course Alerting System"],t.s)
B.a1w=new A.ab(-141,B.ai,271,"TCAS stands for:",B.V9,1,B.L,null,null,null)
B.Vi=s(["8,000 feet","10,000 feet","14,000 feet","12,000 feet"],t.s)
B.a1F=new A.ab(-142,B.ai,272,"At what cabin altitude do passenger oxygen masks automatically deploy?",B.Vi,1,B.A,null,null,null)
B.RE=s(["Provide emergency lighting","Transmit location signal after an accident","Activate the fire suppression system","Alert crew to engine overheat"],t.s)
B.a1O=new A.ab(-143,B.ai,273,"What is the purpose of the ELT?",B.RE,1,B.A,null,null,null)
B.UQ=s([B.a2w,B.a1w,B.a1F,B.a1O],t.C)
B.R2=new A.T(B.a4,"Practice Questions",null,null,null,B.UQ)
