B.Ox=new A.T(B.ac,"Checklists follow fixed language patterns","Aviation checklists use a highly standardized language structure. Unlike conversational English, checklist language is **compressed and precise** \u2014 each word is chosen for accuracy and brevity.\n\nFill-in-the-blank questions test whether you know the correct technical term or phrase for each checklist item.",null,null,null)
B.Oh=new A.T(B.B,"\ud83d\udccb Checklist Language Patterns",'Checklists use three main patterns:\n\n**Challenge / Response:**\n"PARKING BRAKE \u2014 **SET**"\n"SEAT BELTS \u2014 **ON**"\n"FUEL QUANTITY \u2014 **CHECKED**"\n\n**Action items:**\n"\u2026\u2026\u2026 the altimeters to QNH"\n"\u2026\u2026\u2026 the ILS frequency and course"\n"\u2026\u2026\u2026 the transponder to 2000"\n\nCommon action verbs: **set, check, confirm, select, arm, position, verify, engage**',null,null,null)
B.Ks=new A.aE("Set the altimeter to the current QNH of 1013 hectopascals.","Altimetreyi mevcut QNH de\u011feri olan 1013 hektopaskal'a ayarlay\u0131n.","Set")
B.K9=new A.aE("Arm the ground spoilers and confirm flap setting for takeoff.","Yer frenlerini aktif konuma getirin ve kalk\u0131\u015f i\xe7in flap ayar\u0131n\u0131 do\u011frulay\u0131n.","Arm")
B.K_=new A.aE("Verify that all doors are closed and armed before pushback.","Geri itme \xf6ncesinde t\xfcm kap\u0131lar\u0131n kapal\u0131 ve kilitlendi\u011fini do\u011frulay\u0131n.","Verify")
B.Uw=s([B.Ks,B.K9,B.K_],t.l)
B.P5=new A.T(B.ad,"Checklist Phrases in Context",null,B.Uw,null,null)
B.OF=new A.T(B.ae,"\u2708\ufe0f Exam Tip",'Checklist verb distinctions:\n\u2022 **Set** = adjust to a specific value ("set altimeter to 1013")\n\u2022 **Check** = confirm current state without adjusting\n\u2022 **Verify** = confirm a specific condition is met\n\u2022 **Confirm** = obtain acknowledgment from another crew member\n\u2022 **Arm** = place in automatic activation mode\n\u2022 **Select** = choose from available options ("select flaps 5")',null,null,null)
B.SS=s(["Activate","Set","Apply","Lock"],t.s)
B.a1o=new A.ab(-150,B.aF,760,"\u2026\u2026\u2026\u2026 the parking brake before starting engine start procedures.",B.SS,1,B.L,null,null,null)
B.Vg=s(["armed","locked","verified","activated"],t.s)
B.a29=new A.ab(-151,B.aF,761,"Doors and slides \u2014 \u2026\u2026\u2026\u2026 and cross-checked.",B.Vg,0,B.L,null,null,null)
B.UR=s(["Verify","Check","Set","Calibrate"],t.s)
B.a2U=new A.ab(-152,B.aF,762,"\u2026\u2026\u2026\u2026 the standby altimeter to the current field elevation.",B.UR,2,B.A,null,null,null)
B.X8=s(["set","verify","arm","select"],t.s)
B.a1r=new A.ab(-153,B.aF,763,"After engine start, \u2026\u2026\u2026\u2026 the engine oil pressure is within normal limits.",B.X8,1,B.A,null,null,null)
