B.a2r=new A.ab(-101,B.aw,607,"During wet motoring, what is the position of the ignition systems?",B.So,2,B.L,null,null,null)
B.U8=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
